package examples;

import functions.error_handler;
import functions.error_handler_fn;
import jnr.ffi.Memory;
import jnr.ffi.Pointer;
import jnr.ffi.Runtime;
import types.temporal.TInterpolation;

import java.io.*;
import java.time.OffsetDateTime;
import java.util.*;

import static functions.functions.*;

/**
 * A simple program that reads from a CSV file synthetic trip data in
 * Brussels generated by the MobilityDB-BerlinMOD generator,
 * https://github.com/MobilityDB/MobilityDB-BerlinMOD
 * assembles the trips from the individual observations, and write them in a
 * CSV file named "berlinmod_trips_new_assemble.csv" which corresponds to the file
 * "berlinmod_trips.csv" in the data directory.
 *
 * The input file is
 * - `berlinmod_instants.csv`: individual observations from 55 trips of 5 cars
 *   during 4 days obtained from the generator at scale factor 0.005.
 *   This file is generated by the program `05_berlinmod_disassemble`.
 * In the above file, the coordinates are given in the 3857 coordinate system,
 * https://epsg.io/3857
 * and the timestamps are given in the Europe/Brussels time zone.
 */
public class N03_BerlinMOD_Assemble {

    /* Maximum number of instants in an input trip */
    static final int MAX_NO_INSTS = 64000;
    /* Number of instants in a batch for printing a marker */
    static final int NO_INSTS_BATCH = 1000;
    /* Maximum number of trips */
    static final int MAX_TRIPS = 5;
    /* WKB_EXTENDED constant for hexwkb encoding */
    static final byte WKB_EXTENDED = 0x04;

    static class TripRecord {
        int tripId;      /* Identifier of a trip */
        int vehId;       /* Identifier of a vehicle */
        int day;         /* Day of a trip (DateADT) */
        int seq;         /* Sequence number of a trip in a day of a vehicle */
        int numInstants; /* Number of input instants */
        List<Pointer> tripInstants; /* List of instants for a trip */

        TripRecord() {
            tripInstants = new ArrayList<>();
            numInstants = 0;
        }
    }

    /**
     * Helper method to create a Pointer array from a List of Pointers
     */
    private static Pointer createPointerArray(List<Pointer> pointers) {
        Runtime runtime = Runtime.getSystemRuntime();
        Pointer array = Memory.allocate(runtime, pointers.size() * Long.BYTES);
        for (int i = 0; i < pointers.size(); i++) {
            array.putPointer(i * Long.BYTES, pointers.get(i));
        }
        return array;
    }

    public static void main(String[] args) {
        error_handler_fn errorHandler = new error_handler();

        // Get start time
        long startTime = System.currentTimeMillis();

        // Initialize MEOS
        meos_initialize_timezone("UTC");
        meos_initialize_error_handler(errorHandler);

        // Map to store trips by tripId
        Map<Integer, TripRecord> trips = new HashMap<>();
        int noTrips = 0;

        int noRecords = 0;
        int noNulls = 0;

        try (BufferedReader reader = new BufferedReader(
                new FileReader("src/main/java/examples/data/berlinmod_instants.csv"))) {

            // Read the first line with headers
            String headerLine = reader.readLine();
            if (headerLine == null) {
                System.out.println("Error opening input file");
                meos_finalize();
                return;
            }

            System.out.printf("Reading the instants (one '*' marker every %d instants)%n",
                    NO_INSTS_BATCH);

            // Continue reading the file
            String line;
            while ((line = reader.readLine()) != null) {
                String[] fields = line.split(",");

                if (fields.length != 6) {
                    System.out.println("Record with missing values ignored");
                    noNulls++;
                    continue;
                }

                try {
                    int tripId = Integer.parseInt(fields[0].trim());
                    int vehId = Integer.parseInt(fields[1].trim());
                    String dayStr = fields[2].trim();
                    int seq = Integer.parseInt(fields[3].trim());
                    String pointStr = fields[4].trim();
                    String timestampStr = fields[5].trim();

                    noRecords++;
                    if (noRecords % NO_INSTS_BATCH == 0) {
                        System.out.print("*");
                        System.out.flush();
                    }

                    // Transform the string representing the date into a date value
                    int day = pg_date_in(dayStr);

                    // Transform the string representing the point into a geometry
                    Pointer point = geom_in(pointStr, -1);

                    // Transform the string representing the timestamp into a timestamp value
                    OffsetDateTime t = pg_timestamptz_in(timestampStr, -1);

                    // Create the instant
                    Pointer inst = tpointinst_make(point, t);

                    // Find or create the trip record for this tripId
                    TripRecord trip = trips.get(tripId);
                    if (trip == null) {
                        if (noTrips >= MAX_TRIPS) {
                            System.out.printf("%nThe maximum number of trips in the input file is bigger than %d%n",
                                    MAX_TRIPS);
                            meos_finalize();
                            return;
                        }
                        trip = new TripRecord();
                        trip.tripId = tripId;
                        trip.vehId = vehId;
                        trip.day = day;
                        trip.seq = seq;
                        trips.put(tripId, trip);
                        noTrips++;
                    }

                    if (trip.numInstants >= MAX_NO_INSTS) {
                        System.out.printf("%nThe maximum number of instants for trips in the input file is bigger than %d%n",
                                MAX_NO_INSTS);
                        meos_finalize();
                        return;
                    }

                    // Store the instant
                    trip.tripInstants.add(inst);
                    trip.numInstants++;

                } catch (NumberFormatException e) {
                    System.out.println("Record with invalid values ignored");
                    noNulls++;
                }
            }

        } catch (IOException e) {
            System.out.println("Error reading input file: " + e.getMessage());
            meos_finalize();
            return;
        }

        System.out.printf("%n%d records read from file 'berlinmod_instants.csv'.%n",
                noRecords);
        System.out.printf("%d incomplete records ignored.%n", noNulls);
        System.out.printf("%d trips read.%n", noTrips);

        // Open the output file
        try (BufferedWriter writer = new BufferedWriter(
                new FileWriter("src/main/java/examples/data/berlinmod_trips_new_assemble.csv"))) {

            System.out.println("Assembled trips written to file 'berlinmod_trips_new_assemble.csv'");

            // Write the header line
            writer.write("tripid,vehid,day,seqno,trip\n");

            // Loop for each trip
            for (TripRecord trip : trips.values()) {
                // Construct a trip
                Pointer tripInstantsArray = createPointerArray(trip.tripInstants);
                Pointer tripSeq = tsequence_make(tripInstantsArray, trip.numInstants,
                        true, true, TInterpolation.LINEAR.getValue(), true);

                System.out.printf("TripId: %d, Number of input instants: %d, Distance travelled %f%n",
                        trip.tripId, trip.numInstants, tpoint_length(tripSeq));

                // Write line in the CSV file
                String dayStr = pg_date_out(trip.day);
                String tripStr = temporal_as_hexwkb(tripSeq, WKB_EXTENDED);
                writer.write(String.format("%d,%d,%s,%d,%s%n",
                        trip.tripId, trip.vehId, dayStr, trip.seq, tripStr));
            }

        } catch (IOException e) {
            System.out.println("Error writing output file: " + e.getMessage());
        }

        // Calculate the elapsed time
        long endTime = System.currentTimeMillis();
        double timeTaken = (endTime - startTime) / 1000.0;
        System.out.printf("The program took %f seconds to execute%n", timeTaken);

        // Finalize MEOS
        meos_finalize();
    }
}